import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { clearCart } from '../store/slices/cartSlice';
import PaymentModal from '../components/Payment/PaymentModal';
import PaymentSuccess from '../components/Payment/PaymentSuccess';
import PaymentFailure from '../components/Payment/PaymentFailure';
import LocationPicker from '../components/Location/LocationPicker';

const CheckoutRazorpay = () => {
  const [deliveryAddress, setDeliveryAddress] = useState({
    street: '',
    city: 'Chennai',
    state: 'Tamil Nadu',
    zipCode: '',
    country: 'IN',
  });
  const [deliveryInstructions, setDeliveryInstructions] = useState('');
  const [selectedAddress, setSelectedAddress] = useState('');
  const [showPayment, setShowPayment] = useState(false);
  const [showPaymentSuccess, setShowPaymentSuccess] = useState(false);
  const [showPaymentFailure, setShowPaymentFailure] = useState(false);
  const [paymentData, setPaymentData] = useState(null);
  const [orderData, setOrderData] = useState(null);
  const [paymentError, setPaymentError] = useState(null);
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [useCurrentLocation, setUseCurrentLocation] = useState(false);

  const dispatch = useDispatch();
  const navigate = useNavigate();

  const { items, totalAmount, restaurant } = useSelector((state) => state.cart);
  const { user } = useSelector((state) => state.auth);

  const deliveryFee = 25;
  const gst = 20;
  const finalTotal = totalAmount + deliveryFee + gst;

  // Mock saved addresses for Chennai
  const savedAddresses = [
    {
      id: '1',
      label: 'Home',
      street: '123 Anna Nagar Main Road',
      city: 'Chennai',
      state: 'Tamil Nadu',
      zipCode: '600040',
      country: 'IN',
    },
    {
      id: '2',
      label: 'Work',
      street: '456 T. Nagar Commercial Street',
      city: 'Chennai',
      state: 'Tamil Nadu',
      zipCode: '600017',
      country: 'IN',
    },
  ];

  useEffect(() => {
    if (items.length === 0) {
      navigate('/cart');
    }
  }, [items, navigate]);

  const handleAddressSelect = (address) => {
    setSelectedAddress(address.id);
    setDeliveryAddress(address);
  };

  const handleProceedToPayment = () => {
    if (!deliveryAddress.street || !deliveryAddress.city) {
      alert('Please provide a complete delivery address');
      return;
    }

    const newOrderData = {
      id: 'ORD' + Date.now(),
      items,
      restaurant,
      totalAmount: finalTotal,
      deliveryAddress,
      deliveryInstructions,
      userId: user?.id,
      createdAt: new Date().toISOString(),
      status: 'pending'
    };

    setOrderData(newOrderData);
    setShowPayment(true);
  };

  const handlePaymentSuccess = (payment) => {
    setPaymentData(payment);

    // Save order to localStorage
    const orders = JSON.parse(localStorage.getItem('orders') || '[]');
    const completedOrder = {
      ...orderData,
      paymentMethod: payment.paymentMethod,
      paymentStatus: payment.paymentStatus,
      paymentId: payment.paymentId,
      status: payment.paymentMethod === 'cod' ? 'confirmed' : 'confirmed'
    };
    orders.push(completedOrder);
    localStorage.setItem('orders', JSON.stringify(orders));

    // Clear cart
    dispatch(clearCart());

    setShowPayment(false);
    setShowPaymentSuccess(true);
  };

  const handlePaymentFailure = (error) => {
    setPaymentError(error);
    setShowPayment(false);
    setShowPaymentFailure(true);
  };

  const handleRetryPayment = () => {
    setShowPaymentFailure(false);
    setPaymentError(null);
    setShowPayment(true);
  };

  const handleCloseSuccess = () => {
    setShowPaymentSuccess(false);
    navigate('/');
  };

  const handleCloseFailure = () => {
    setShowPaymentFailure(false);
    setPaymentError(null);
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="bg-white rounded-lg shadow-sm">
          <div className="px-6 py-4 border-b border-gray-200">
            <h1 className="text-2xl font-bold text-gray-900">Checkout</h1>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 p-6">
            {/* Left Column - Address & Instructions */}
            <div className="space-y-6">
              {/* Saved Addresses */}
              <div>
                <h2 className="text-lg font-semibold text-gray-900 mb-4">Delivery Address</h2>
                <div className="space-y-3">
                  {savedAddresses.map((address) => (
                    <div
                      key={address.id}
                      className={`border rounded-lg p-4 cursor-pointer transition-colors ${
                        selectedAddress === address.id
                          ? 'border-orange-500 bg-orange-50'
                          : 'border-gray-200 hover:border-gray-300'
                      }`}
                      onClick={() => handleAddressSelect(address)}
                    >
                      <div className="flex items-center justify-between">
                        <div>
                          <div className="font-medium text-gray-900">{address.label}</div>
                          <div className="text-sm text-gray-600">
                            {address.street}, {address.city}, {address.state} {address.zipCode}
                          </div>
                        </div>
                        <input
                          type="radio"
                          name="address"
                          checked={selectedAddress === address.id}
                          onChange={() => handleAddressSelect(address)}
                          className="text-orange-600"
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* New Address Form */}
              <div>
                <h3 className="text-md font-medium text-gray-900 mb-4">Or add a new address</h3>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Street Address
                    </label>
                    <input
                      type="text"
                      value={deliveryAddress.street}
                      onChange={(e) =>
                        setDeliveryAddress({ ...deliveryAddress, street: e.target.value })
                      }
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                      placeholder="Enter your street address"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        City
                      </label>
                      <input
                        type="text"
                        value={deliveryAddress.city}
                        onChange={(e) =>
                          setDeliveryAddress({ ...deliveryAddress, city: e.target.value })
                        }
                        className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                        placeholder="City"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        PIN Code
                      </label>
                      <input
                        type="text"
                        value={deliveryAddress.zipCode}
                        onChange={(e) =>
                          setDeliveryAddress({ ...deliveryAddress, zipCode: e.target.value })
                        }
                        className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                        placeholder="PIN Code"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Delivery Instructions (Optional)
                    </label>
                    <textarea
                      value={deliveryInstructions}
                      onChange={(e) => setDeliveryInstructions(e.target.value)}
                      rows={3}
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                      placeholder="Any special instructions for delivery..."
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Right Column - Order Summary */}
            <div>
              <div className="bg-gray-50 rounded-lg p-6">
                <h2 className="text-lg font-semibold text-gray-900 mb-4">Order Summary</h2>

                {/* Restaurant Info */}
                {restaurant && (
                  <div className="flex items-center mb-4 pb-4 border-b border-gray-200">
                    <img
                      src={restaurant.image}
                      alt={restaurant.name}
                      className="w-12 h-12 object-cover rounded-lg"
                    />
                    <div className="ml-3">
                      <div className="font-medium text-gray-900">{restaurant.name}</div>
                      <div className="text-sm text-gray-600">{restaurant.cuisine}</div>
                    </div>
                  </div>
                )}

                {/* Order Items */}
                <div className="space-y-3 mb-4">
                  {items.map((item) => (
                    <div key={item.id} className="flex justify-between items-center">
                      <div className="flex-1">
                        <div className="font-medium text-gray-900">{item.name}</div>
                        <div className="text-sm text-gray-600">Qty: {item.quantity}</div>
                      </div>
                      <div className="font-medium text-gray-900">
                        ₹{(item.price * item.quantity).toFixed(2)}
                      </div>
                    </div>
                  ))}
                </div>

                {/* Price Breakdown */}
                <div className="space-y-2 border-t border-gray-200 pt-4">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Subtotal</span>
                    <span className="text-gray-900">₹{totalAmount.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Delivery Fee</span>
                    <span className="text-gray-900">₹{deliveryFee.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-600">GST</span>
                    <span className="text-gray-900">₹{gst.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-lg font-semibold border-t border-gray-200 pt-2">
                    <span className="text-gray-900">Total</span>
                    <span className="text-gray-900">₹{finalTotal.toFixed(2)}</span>
                  </div>
                </div>

                {/* Proceed to Payment Button */}
                <button
                  onClick={handleProceedToPayment}
                  disabled={!deliveryAddress.street || !deliveryAddress.city}
                  className="w-full mt-6 bg-orange-500 text-white py-3 px-4 rounded-lg font-semibold hover:bg-orange-600 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
                >
                  Proceed to Payment
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Payment Modal */}
      <PaymentModal
        isOpen={showPayment}
        onClose={() => setShowPayment(false)}
        orderData={orderData}
        onPaymentSuccess={handlePaymentSuccess}
        onPaymentFailure={handlePaymentFailure}
      />

      {/* Payment Success Modal */}
      {showPaymentSuccess && (
        <PaymentSuccess
          paymentData={paymentData}
          orderData={orderData}
          onClose={handleCloseSuccess}
        />
      )}

      {/* Payment Failure Modal */}
      {showPaymentFailure && (
        <PaymentFailure
          error={paymentError}
          orderData={orderData}
          onRetry={handleRetryPayment}
          onClose={handleCloseFailure}
        />
      )}
    </div>
  );
};

export default CheckoutRazorpay;
